    unvisited_count = len(unvisited_customers)
    min_waiting_time = float('inf')
    best_node = None

    for i in range(unvisited_count):
        customer_pos = unvisited_customers[i]
        travel_t = travel_time(cur_truck_pos, customer_pos)
