import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(from_pos, to_pos, speed):
        return np.linalg.norm(to_pos - from_pos) / speed

    def calculate_slack(time_now, window):
        return max(0, window[0] - time_now)

    def calculate_urgency(time_now, window):
        if time_now > window[1]:
            return float('inf')
        return max(0, window[1] - time_now)

    min_cost = float('inf')
    best_node = None

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
        arrival_time = current_time + travel_time
        window = time_windows[idx]

        # Calculate priority based on urgency and slack
        urgency = calculate_urgency(arrival_time, window)
        slack = calculate_slack(arrival_time, window)

        # Cost function to minimize
        cost = travel_time + urgency - slack

        if cost < min_cost:
            min_cost = cost
            best_node = idx

    return best_node

