def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def calculate_arrival_time(pos, destination):
        return current_time + (euclidean_distance(pos, destination) / truck_speed)

    num_customers = len(unvisited_customers)
    min_time_penalty = float('inf')
    best_node = None

    for i in range(num_customers):
        customer_pos = unvisited_customers[i]
        window_start, window_end = time_windows[i]
        arrival_time = calculate_arrival_time(cur_truck_pos, customer_pos)

        if arrival_time < window_start:
            # Consider waiting cost
            wait_time = window_start - arrival_time
            time_cost = current_time + wait_time + (euclidean_distance(cur_truck_pos, customer_pos) / truck_speed)
        else:
            time_cost = arrival_time

        if time_cost < window_end:
            penalty = max(0, (window_end - time_cost))  # smaller penalty if within or close to the end time
        else:
            penalty = (time_cost - window_end) * 10  # larger penalty the later we are

        # Check if this choice can potentially improve synchronization with other trucks
        synchronization_cost = 0
        for t_pos in all_truck_pos:
            if np.array_equal(t_pos, cur_truck_pos):
                continue
            sync_arrival_time = calculate_arrival_time(t_pos, customer_pos)
            synchronization_cost += abs(sync_arrival_time - time_cost)

        overall_cost = time_cost + penalty + synchronization_cost

        if overall_cost < min_time_penalty:
            min_time_penalty = overall_cost
            best_node = i

    return best_node
